#canvas {

    position: absolute;

    left: 50%;

    top: 50%;

    transform: translate(-50%, -50%);

    background-color: #f7f7f7;

}

.ball {

    position: absolute;

    width: 50px;

    height: 50px;

    border-radius: 50%;

    background-color: red;

}

starterCode.javascript:
// Create a canvas element and get its 2D drawing context.

var canvas = document.getElementById('canvas');

var ctx = canvas.getContext('2d');



// Set the canvas dimensions.

canvas.width = window.innerWidth;

canvas.height = window.innerHeight;



// Get the canvas dimensions.

var centerX = canvas.width / 2;

var centerY = canvas.height / 2;



// Create a ball object.

var ball = {

    x: centerX,

    y: centerY,

    radius: 25,

    speedX: 0,

    speedY: 2

};



// Draw a ball on the canvas.

function draw() {

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    ctx.beginPath();

    ctx.arc(ball.x, ball.y, ball.radius, 0, 2 * Math.PI);

    ctx.fillStyle = 'red';

    ctx.fill();

}



// Update the ball position based on its speed.

function update() {

    ball.x += ball.speedX;

    ball.y += ball.speedY;



    // Check if the ball has bounced off the bottom of the canvas.

    if (ball.y + ball.radius > canvas.height) {

        ball.speedY = -ball.speedY;

    }

}



// Animate the ball.

function animate() {

    update();

    draw();



    // Request the next animation frame.

    requestAnimationFrame(animate);

}



// Start the animation.

animate();

